// In Controller
app.post('/api/orders', async (req, res) => {
  const { userId, items } = req.body;
  if (!userId) return res.status(400).send('User ID is required');

  // Direct database query
  const activeOrder = await db.query('SELECT * FROM orders WHERE user_id = $1 AND status = \'ACTIVE\'', [userId]);
  if (activeOrder.rows.length > 0) {
    return res.status(409).send('Each user can have only one active order');
  }

  const order = {
    id: generateUUID(),
    userId,
    items,
    status: 'ACTIVE',
    createdAt: new Date()
  };
  await db.query('INSERT INTO orders (id, user_id, items, status, created_at) VALUES ($1, $2, $3, $4, $5)', [order.id, order.userId, JSON.stringify(order.items), order.status, order.createdAt]);

  res.status(201).json(order);
});
